// Pidä vain .md-tiedostot ja poimi latauslinkit
return $input.all()
  .filter(i => i.json.name && i.json.name.endsWith('.md'))
  .map(i => ({ json: { name: i.json.name, url: i.json.download_url } }));

// Kokoa kaikki liidikortit yhdeksi aineistoksi + rakenna promptit
const nimet = $('Suodata md-tiedostot').all();
const kortit = $input.all().map((item, i) => {
  const nimi = nimet[i] ? nimet[i].json.name : 'tuntematon';
  return `===== LIIDIKORTTI: ${nimi} =====
${item.json.data}`;
});
const tanaan = new Date().toLocaleDateString('fi-FI', { weekday: 'long', year: 'numeric', month: 'numeric', day: 'numeric', timeZone: 'Europe/Helsinki' });
const pvm = new Date().toLocaleDateString('sv-SE', { timeZone: 'Europe/Helsinki' });

const systemPrompt = `Olet Flowlyn myyntiassistentti. Tuota aamuraportti suomeksi. Tänään on ${tanaan}.

Saat aineistona liidikortteja Obsidian-vaultista. Korteissa on: status-tagit (#status/uusi, #status/soitettu, #status/kiinnostunut, #status/tarjous, #status/asiakas, #status/myöhemmin), pisteet 0-100, päättäjän yhteystiedot, valmiit liidit asiakkaalle, ja Seuraava askel + päivämäärä.

RAPORTIN RAKENNE (tässä järjestyksessä, max noin 2500 merkkiä yhteensä):
1. RAHA TÄNÄÄN: 1-3 toimenpidettä jotka todennäköisimmin tuovat rahaa tänään (kiinnostuneet lähellä päätöstä, erääntyvät follow-upit, toimitettavat testipaketit). Perustelu 1 lause.
2. SOITTOLISTA: max 10 yritystä pisteytysjärjestyksessä. Jokaisesta: nimi, numero, pisteet, miksi juuri tänään, ja 1 avauslause juuri tälle firmalle.
3. FOLLOW-UPIT: kortit joiden Seuraava askel -päivämäärä on tänään tai mennyt. Mainitse mitä viimeksi sovittiin.
4. JUMISSA: #status/tarjous-kortit ilman etenemistä - ehdota pelastusliike.
5. PÄIVÄN FOKUS: 1 myyntitaito + 1 vastaväite harjoiteltavaksi.

SÄÄNNÖT: Suora suomi, ei hypeä, ei tekoälyjargonia. Älä keksi dataa - jos jokin osio on tyhjä, sano se yhdellä rivillä. Älä ehdota työkalujen rakentamista. Muotoile Telegram-yhteensopivasti: ei markdown-taulukoita, käytä rivinvaihtoja ja isoja otsikkorivejä.`;

return [{ json: { aineisto: kortit.join('

'), systemPrompt, pvm } }];

// Valmistele Telegram-viesti ja GitHub-commit
const raportti = $json.choices[0].message.content;
const pvm = $('Kokoa aineisto ja prompt').first().json.pvm;
const tiedosto = `# ${pvm} Aamuraportti\n\n${raportti}`;
return [{ json: {
  teksti: raportti.length > 3900 ? raportti.slice(0, 3900) + '\n(...katkaistu, koko raportti Obsidianissa)' : raportti,
  base64: Buffer.from(tiedosto, 'utf-8').toString('base64'),
  polku: `09 - Myynti/00 - Ohjaus/${pvm} Aamuraportti.md`,
  pvm
} }];
